VALUES
  ('social-worker-moex-05190', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區工作相關理論的敘述，下列何者錯誤？', '["生態系統的取徑促使社區工作者認清問題的發生，是來自於「一個人的環境及其需求、能力與 想望的巨大落差」", "社區工作因為工作對象、工作區域與價值的不同，會選取單一理論模式來協助社區、社區居民 內部或外部的特定問題", "社區培力（community empowerment）提供社區工作者一個更寬廣的實踐脈絡，提出社會正義、 多樣性與平等，和創造社區利益一樣，都是必須要受到重視的議題", "社區網絡建構（community networking）提到在社區中服務使用者的網絡以及與各種機構之間 的連結，通常會成為評估正式與非正式支持是否混配合宜的基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
